723	    fn attr_value_len(&mut self, value: &AttributeValue) -> usize {
724	        match value {
725	            AttributeValue::IfExpr(if_chain) => {
726	                let condition_len = self.retrieve_formatted_expr(&if_chain.if_expr.cond).len();
727	                let value_len = self.attr_value_len(&if_chain.then_value);
728	                let if_len = 2;
729	                let brace_len = 2;
730	                let space_len = 2;
731	                let else_len = if_chain
732	                    .else_value
733	                    .as_ref()
734	                    .map(|else_value| self.attr_value_len(else_value) + 1)
735	                    .unwrap_or_default();
736	                condition_len + value_len + if_len + brace_len + space_len + else_len
737	            }
738	            AttributeValue::AttrLiteral(lit) => lit.to_string().len(),
739	            AttributeValue::Shorthand(expr) => {
740	                let span = &expr.span();
741	                span.end().line - span.start().line
742	            }
743	            AttributeValue::AttrExpr(expr) => expr
744	                .as_expr()
745	                .map(|expr| {
746	                    if self.span_has_line_comments(expr.span()) {
747	                        100000
748	                    } else {
749	                        self.attr_expr_len(&expr)
750	                    }
751	                })
752	                .unwrap_or(100000),
753	            AttributeValue::EventTokens(closure) => closure
754	                .as_expr()
755	                .map(|expr| {
756	                    if self.span_has_line_comments(expr.span()) {
757	                        100000
758	                    } else {
759	                        self.attr_expr_len(&expr)
760	                    }
761	                })
762	                .unwrap_or(100000),
763	        }
764	    }
