775	    fn is_short_attrs(
776	        &mut self,
777	        _brace: &Brace,
778	        attributes: &[Attribute],
779	        spreads: &[Spread],
780	    ) -> usize {
781	        let mut total = 0;
782	
783	        // No more than 3 attributes before breaking the line
784	        if attributes.len() > 3 {
785	            return 100000;
786	        }
787	
788	        for attr in attributes {
789	            if self.current_span_is_primary(attr.span().start()) {
790	                if let Some(lines) = self.src.get(..attr.span().start().line - 1) {
791	                    'line: for line in lines.iter().rev() {
792	                        match (line.trim().starts_with("//"), line.is_empty()) {
793	                            (true, _) => return 100000,
794	                            (_, true) => continue 'line,
795	                            _ => break 'line,
796	                        }
797	                    }
798	                };
799	            }
800	
801	            total += match &attr.name {
802	                AttributeName::BuiltIn(name) => {
803	                    let name = name.to_string();
804	                    name.len()
805	                }
806	                AttributeName::Custom(name) => name.value().len() + 2,
807	                AttributeName::Spread(_) => unreachable!(),
808	            };
809	
810	            if attr.can_be_shorthand() {
811	                total += 2;
812	            } else {
813	                total += self.attr_value_len(&attr.value);
814	            }
815	
816	            total += 6;
817	        }
818	
819	        for spread in spreads {
820	            let expr_len = self.retrieve_formatted_expr(&spread.expr).len();
821	            total += expr_len + 3;
822	        }
823	
824	        total
825	    }
