857	    fn write_partial_expr(&mut self, expr: syn::Result<Expr>, src_span: Span) -> Result {
858	        let Ok(expr) = expr else {
859	            self.invalid_exprs.push(src_span);
860	            return Err(std::fmt::Error);
861	        };
862	
863	        thread_local! {
864	            static COMMENT_REGEX: Regex = Regex::new("\"[^\"]*\"|(//.*)").unwrap();
865	        }
866	
867	        let pretty = self.retrieve_formatted_expr(&expr).to_string();
868	        let source = src_span.source_text().unwrap_or_default();
869	        let source_has_line_comments = source
870	            .lines()
871	            .any(|line| line.trim_start().starts_with("//"));
872	        let mut src_lines = source.lines().peekable();
873	
874	        // Comments already in pretty output (from nested rsx!) - skip these from source
875	        let pretty_comments: HashSet<_> = pretty
876	            .lines()
877	            .filter(|l| l.trim().starts_with("//"))
878	            .map(|l| l.trim())
879	            .collect();
880	
881	        let mut out = String::new();
882	
883	        if src_lines.peek().is_none() {
884	            out = pretty;
885	        } else {
886	            for line in pretty.lines() {
887	                let trimmed = line.trim();
888	                let compacted = line.replace(" ", "").replace(",", "");
889	
890	                // Pretty comments: consume matching source lines, preserve preceding empty lines
891	                if trimmed.starts_with("//") {
892	                    if !out.is_empty() {
893	                        out.push('\n');
894	                    }
895	                    let mut had_empty = false;
896	                    while let Some(s) = src_lines.peek() {
897	                        let t = s.trim();
898	                        if t.is_empty() {
899	                            had_empty = true;
900	                            src_lines.next();
901	                        } else if t == trimmed {
902	                            src_lines.next();
903	                            break;
904	                        } else {
905	                            break;
906	                        }
907	                    }
908	                    if had_empty {
909	                        out.push('\n');
910	                    }
911	                    out.push_str(line);
912	                    continue;
913	                }
914	
915	                // Pretty empty lines: preserve and sync with source
916	                if trimmed.is_empty() {
917	                    if !out.is_empty() {
918	                        out.push('\n');
919	                    }
920	                    while src_lines
921	                        .peek()
922	                        .map(|s| s.trim().is_empty())
923	                        .unwrap_or(false)
924	                    {
925	                        src_lines.next();
926	                    }
927	                    continue;
928	                }
929	
930	                if !out.is_empty() {
931	                    out.push('\n');
932	                }
933	
934	                // Scan source for comments/empty lines before the matching line
935	                let mut pending_comments = Vec::new();
936	                let mut had_empty = false;
937	                let mut multiline: Option<Vec<&str>> = None;
938	
939	                while let Some(src) = src_lines.peek() {
940	                    let src_trimmed = src.trim();
941	
942	                    if src_trimmed.is_empty() || src_trimmed.starts_with("//") {
943	                        if src_trimmed.is_empty() {
944	                            if pending_comments.is_empty() {
945	                                had_empty = true;
946	                            }
947	                        } else if !pretty_comments.contains(src_trimmed) {
948	                            pending_comments.push(src_trimmed);
949	                        }
950	                        src_lines.next();
951	                        continue;
952	                    }
953	
954	                    let src_compacted = src.replace(" ", "").replace(",", "");
955	
956	                    // Exact match
957	                    if src_compacted.contains(&compacted) {
958	                        break;
959	                    }
960	
961	                    // Multi-line method chain (e.g., foo\n  .bar()\n  .baz())
962	                    if !src_compacted.is_empty() && compacted.starts_with(&src_compacted) {
963	                        let is_call = src_trimmed.ends_with('(')
964	                            || src_trimmed.ends_with(',')
965	                            || src_trimmed.ends_with('{');
966	                        let is_commented_block =
967	                            source_has_line_comments && src_trimmed.ends_with('{');
968	                        if is_commented_block || !is_call {
969	                            multiline = Some(vec![*src]);
970	                            break;
971	                        }
972	                    }
973	
974	                    // Non-matching line - clear pending and skip
975	                    pending_comments.clear();
976	                    had_empty = false;
977	                    src_lines.next();
978	                    break;
979	                }
980	
981	                // Output empty line if needed
982	                if had_empty {
983	                    out.push('\n');
984	                }
985	
986	                // Output pending comments
987	                for comment in &pending_comments {
988	                    for c in line.chars().take_while(|c| c.is_whitespace()) {
989	                        out.push(c);
990	                    }
991	                    if matches!(trimmed.chars().next(), Some(')' | '}' | ']')) {
992	                        out.push_str(self.out.indent.indent_str());
993	                    }
994	                    out.push_str(comment);
995	                    out.push('\n');
996	                }
997	
998	                // Handle multi-line method chains
999	                if let Some(mut ml) = multiline {
1000	                    src_lines.next();
1001	                    let mut acc = ml[0].replace(" ", "").replace(",", "");
1002	
1003	                    while let Some(src) = src_lines.peek() {
1004	                        let t = src.trim();
1005	                        if t.starts_with("//") {
1006	                            ml.push(src);
1007	                            src_lines.next();
1008	                            continue;
1009	                        }
1010	                        if t.is_empty() {
1011	                            src_lines.next();
1012	                            continue;
1013	                        }
1014	
1015	                        acc.push_str(&src.replace(" ", "").replace(",", ""));
1016	                        ml.push(src);
1017	
1018	                        if acc.contains(&compacted) {
1019	                            src_lines.next();
1020	                            break;
1021	                        }
1022	
1023	                        let cont = t.starts_with('.')
1024	                            || t.starts_with("&&")
1025	                            || t.starts_with("||")
1026	                            || matches!(t.chars().next(), Some('+' | '-' | '*' | '/' | '?'));
1027	
1028	                        if cont || compacted.starts_with(&acc) {
1029	                            src_lines.next();
1030	                            continue;
1031	                        }
1032	                        break;
1033	                    }
1034	
1035	                    // Write multi-line with adjusted indentation
1036	                    let base_indent = if source_has_line_comments && ml[0].trim_end().ends_with('{')
1037	                    {
1038	                        ml.iter()
1039	                            .skip(1)
1040	                            .filter(|line| !line.trim().is_empty())
1041	                            .map(|line| line.chars().take_while(|c| c.is_whitespace()).count())
1042	                            .min()
1043	                            .unwrap_or(0)
1044	                    } else {
1045	                        ml[0].chars().take_while(|c| c.is_whitespace()).count()
1046	                    };
1047	                    let target: String = line.chars().take_while(|c| c.is_whitespace()).collect();
1048	
1049	                    for (i, src_line) in ml.iter().enumerate() {
1050	                        let indent = src_line.chars().take_while(|c| c.is_whitespace()).count();
1051	                        out.push_str(&target);
1052	                        for _ in 0..indent.saturating_sub(base_indent) {
1053	                            out.push(' ');
1054	                        }
1055	                        out.push_str(src_line.trim());
1056	                        if i < ml.len() - 1 {
1057	                            out.push('\n');
1058	                        }
1059	                    }
1060	                } else {
1061	                    // Single line - output pretty line and capture inline comments
1062	                    out.push_str(line);
1063	                    if let Some(src_line) = src_lines.next() {
1064	                        if let Some(cap) = COMMENT_REGEX.with(|r| r.captures(src_line)) {
1065	                            if let Some(c) = cap.get(1) {
1066	                                out.push_str(" // ");
1067	                                out.push_str(c.as_str().replace("//", "").trim());
1068	                            }
1069	                        }
1070	                    }
1071	                }
1072	            }
1073	        }
1074	
1075	        self.write_mulitiline_tokens(out)?;
1076	        Ok(())
1077	    }
