1079	    fn write_mulitiline_tokens(&mut self, out: String) -> Result {
1080	        let mut lines = out.split('\n').peekable();
1081	        let first = lines.next().unwrap();
1082	
1083	        // a one-liner for whatever reason
1084	        // Does not need a new line
1085	        if lines.peek().is_none() {
1086	            write!(self.out, "{first}")?;
1087	        } else {
1088	            writeln!(self.out, "{first}")?;
1089	
1090	            while let Some(line) = lines.next() {
1091	                if !line.trim().is_empty() {
1092	                    self.out.tab()?;
1093	                }
1094	
1095	                write!(self.out, "{line}")?;
1096	                if lines.peek().is_none() {
1097	                    write!(self.out, "")?;
1098	                } else {
1099	                    writeln!(self.out)?;
1100	                }
1101	            }
1102	        }
1103	
1104	        Ok(())
1105	    }
