1123	    // check if the children are short enough to be on the same line
1124	    // We don't have the notion of current line depth - each line tries to be < 80 total
1125	    // returns the total line length if it's short
1126	    // returns none if the length exceeds the limit
1127	    // I think this eventually becomes quadratic :(
1128	    fn is_short_children(&mut self, children: &[BodyNode]) -> syn::Result<Option<usize>> {
1129	        if children.is_empty() {
1130	            return Ok(Some(0));
1131	        }
1132	
1133	        // Any comments push us over the limit automatically
1134	        if self.children_have_comments(children) {
1135	            return Ok(None);
1136	        }
1137	
1138	        let res = match children {
1139	            [BodyNode::Text(ref text)] => Some(text.input.to_string_with_quotes().len()),
1140	
1141	            // TODO: let rawexprs to be inlined
1142	            [BodyNode::RawExpr(ref expr)] => {
1143	                let pretty = self.retrieve_formatted_expr(&expr.expr.as_expr()?);
1144	                if pretty.contains('\n') {
1145	                    None
1146	                } else {
1147	                    Some(pretty.len() + 2)
1148	                }
1149	            }
1150	
1151	            // TODO: let rawexprs to be inlined
1152	            [BodyNode::Component(ref comp)]
1153	            // basically if the component is completely empty, we can inline it
1154	                if comp.fields.is_empty()
1155	                    && comp.children.is_empty()
1156	                    && comp.spreads.is_empty() =>
1157	            {
1158	                Some(
1159	                    comp.name
1160	                        .segments
1161	                        .iter()
1162	                        .map(|s| s.ident.to_string().len() + 2)
1163	                        .sum::<usize>(),
1164	                )
1165	            }
1166	
1167	            // Feedback on discord indicates folks don't like combining multiple children on the same line
1168	            // We used to do a lot of math to figure out if we should expand out the line, but folks just
1169	            // don't like it.
1170	            _ => None,
1171	        };
1172	
1173	        Ok(res)
1174	    }
