1214	    fn retrieve_formatted_expr(&mut self, expr: &Expr) -> Cow<'_, str> {
1215	        let loc = expr.span().start();
1216	
1217	        // never cache expressions that are spanless
1218	        if loc.line == 1 && loc.column == 0 {
1219	            return self.unparse_expr(expr).into();
1220	        }
1221	
1222	        if !self.cached_formats.contains_key(&loc) {
1223	            let formatted = self.unparse_expr(expr);
1224	            self.cached_formats.insert(loc, formatted);
1225	        }
1226	
1227	        self.cached_formats
1228	            .get(&loc)
1229	            .expect("Just inserted the parsed expr, so it should be in the cache")
1230	            .as_str()
1231	            .into()
1232	    }
