1234	    fn final_span_of_node(node: &BodyNode) -> Span {
1235	        // Get the ending span of the node
1236	        match node {
1237	            BodyNode::Element(el) => el
1238	                .brace
1239	                .as_ref()
1240	                .map(|b| b.span.span())
1241	                .unwrap_or_else(|| el.name.span()),
1242	            BodyNode::Component(el) => el
1243	                .brace
1244	                .as_ref()
1245	                .map(|b| b.span.span())
1246	                .unwrap_or_else(|| el.name.span()),
1247	            BodyNode::Text(txt) => txt.input.span(),
1248	            BodyNode::RawExpr(exp) => exp.span(),
1249	            BodyNode::ForLoop(f) => f.brace.span.span(),
1250	            BodyNode::IfChain(i) => match i.else_brace {
1251	                Some(b) => b.span.span(),
