1274	    fn has_trailing_comments(&self, children: &[BodyNode], brace: &Brace) -> bool {
1275	        let brace_span = brace.span.span();
1276	
1277	        let Some(last_node) = children.last() else {
1278	            return false;
1279	        };
1280	
1281	        // Check for any comments after the last node between the last brace
1282	        let final_span = Self::final_span_of_node(last_node);
1283	        let final_span = final_span.end();
1284	        let mut line = final_span.line;
1285	        let mut column = final_span.column;
1286	        loop {
1287	            let Some(src_line) = self.src.get(line - 1) else {
1288	                return false;
1289	            };
1290	
1291	            // the line might contain emoji or other unicode characters - this will cause issues
1292	            let Some(mut whitespace) = src_line.get(column..).map(|s| s.trim()) else {
1293	                return false;
1294	            };
1295	
1296	            let offset = 0;
1297	            whitespace = whitespace[offset..].trim();
1298	
1299	            if whitespace.starts_with("//") {
1300	                return true;
1301	            }
